const nodeCrypto=require("node:crypto");module.exports={postgresMd5PasswordHash,randomBytes,deriveKey,sha256,hashByName,hmacSha256,md5};const webCrypto=nodeCrypto.webcrypto||globalThis.crypto,subtleCrypto=webCrypto.subtle,textEncoder=new TextEncoder;function randomBytes(t){return webCrypto.getRandomValues(Buffer.alloc(t))}async function md5(t){try{return nodeCrypto.createHash("md5").update(t,"utf-8").digest("hex")}catch{const a=typeof t=="string"?textEncoder.encode(t):t,n=await subtleCrypto.digest("MD5",a);return Array.from(new Uint8Array(n)).map(r=>r.toString(16).padStart(2,"0")).join("")}}async function postgresMd5PasswordHash(t,e,a){const n=await md5(e+t);return"md5"+await md5(Buffer.concat([Buffer.from(n),a]))}async function sha256(t){return await subtleCrypto.digest("SHA-256",t)}async function hashByName(t,e){return await subtleCrypto.digest(t,e)}async function hmacSha256(t,e){const a=await subtleCrypto.importKey("raw",t,{name:"HMAC",hash:"SHA-256"},!1,["sign"]);return await subtleCrypto.sign("HMAC",a,textEncoder.encode(e))}async function deriveKey(t,e,a){const n=await subtleCrypto.importKey("raw",textEncoder.encode(t),"PBKDF2",!1,["deriveBits"]),r={name:"PBKDF2",hash:"SHA-256",salt:e,iterations:a};return await subtleCrypto.deriveBits(r,n,256,["deriveBits"])}
